settings.custom_liquid:
{%- assign phone_number = "+33767422570" -%}
<div class="phone-banner-compact">
  <div class="phone-banner-compact__wrapper">
    <div class="phone-banner-compact__info">
      <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5">
        <path d="M22 16.92v3a2 2 0 0 1-2.18 2 19.79 19.79 0 0 1-8.63-3.07 19.5 19.5 0 0 1-6-6 19.79 19.79 0 0 1-3.07-8.67A2 2 0 0 1 4.11 2h3a2 2 0 0 1 2 1.72 12.84 12.84 0 0 0 .7 2.81 2 2 0 0 1-.45 2.11L8.09 9.91a16 16 0 0 0 6 6l1.27-1.27a2 2 0 0 1 2.11-.45 12.84 12.84 0 0 0 2.81.7A2 2 0 0 1 22 16.92z"></path>
      </svg>
      <div>
        <span class="phone-banner-compact__label">Besoin d'un aperçu du volant ?</span>
        <a href="tel:{{ phone_number }}" class="phone-banner-compact__number">{{ phone_number }}</a>
      </div>
    </div>
    <button class="phone-banner-compact__copy js-copy-phone-compact" title="Copier le numéro">
      <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5">
        <rect x="9" y="9" width="13" height="13" rx="2" ry="2"></rect>
        <path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1"></path>
      </svg>
    </button>
  </div>
</div>

<script>
document.addEventListener('DOMContentLoaded', function() {
  const copyBtn = document.querySelector('.js-copy-phone-compact');
  if (copyBtn) {
    copyBtn.addEventListener('click', function() {
      navigator.clipboard.writeText('{{ phone_number }}').then(function() {
        const originalHTML = copyBtn.innerHTML;
        copyBtn.innerHTML = '<svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><path d="M20 6L9 17l-5-5"></path></svg>';
        copyBtn.classList.add('copied');
        setTimeout(function() {
          copyBtn.innerHTML = originalHTML;
          copyBtn.classList.remove('copied');
        }, 2000);
      });
    });
  }
});
</script>

<style>
.phone-banner-compact {
  width: 100%;
  max-width: 500px;
  margin: 1.5rem auto;
}

.phone-banner-compact__wrapper {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 1rem;
  padding: 1rem 1.25rem;
  background: linear-gradient(45deg, #1e3a8a, #3b82f6, #1e3a8a, #3b82f6);
  background-size: 300% 300%;
  animation: gradient-shift 4s ease infinite;
  border-radius: 12px;
  box-shadow: 0 4px 12px rgba(30, 58, 138, 0.25);
}

.phone-banner-compact__info {
  display: flex;
  align-items: center;
  gap: 0.875rem;
  color: white;
}

.phone-banner-compact__info > svg {
  flex-shrink: 0;
}

.phone-banner-compact__label {
  display: block;
  font-size: 0.9rem;
  color: #e0e7ff;
  font-weight: 600;
  margin-bottom: 0.25rem;
  text-shadow: 0 1px 2px rgba(0, 0, 0, 0.1);
}

.phone-banner-compact__number {
  display: block;
  font-size: 1.25rem;
  font-weight: 700;
  color: white;
  text-decoration: none;
  letter-spacing: 0.025em;
  text-shadow: 0 2px 4px rgba(0, 0, 0, 0.15);
}

.phone-banner-compact__number:hover {
  text-decoration: underline;
}

.phone-banner-compact__copy {
  flex-shrink: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  width: 40px;
  height: 40px;
  background: rgba(255, 255, 255, 0.2);
  border: none;
  border-radius: 8px;
  color: white;
  cursor: pointer;
  transition: all 0.2s ease;
  backdrop-filter: blur(10px);
}

.phone-banner-compact__copy:hover {
  background: rgba(255, 255, 255, 0.3);
  transform: scale(1.05);
}

.phone-banner-compact__copy.copied {
  background: rgba(16, 185, 129, 0.9);
}

@media screen and (max-width: 640px) {
  .phone-banner-compact {
    margin: 1rem auto;
  }

  .phone-banner-compact__wrapper {
    padding: 0.875rem 1rem;
  }

  .phone-banner-compact__label {
    font-size: 0.85rem;
  }

  .phone-banner-compact__number {
    font-size: 1.125rem;
  }
}
</style>
